begin;

values (
  'kempape-2026',
  'Kempape 2026',
  'Europe/Berlin',
  '2026-07-16T11:30:00+02:00',
  '2026-07-20T03:00:00+02:00',
  '{"cycleCount":4,"finalMidnightCreatesNewCycle":false}'::jsonb
)
on conflict (id) do update set
  name = excluded.name,
  time_zone = excluded.time_zone,
  starts_at = excluded.starts_at,
  ends_at = excluded.ends_at,
  config = excluded.config;


commit;
